/* === D&D 2024 App — Apex Dark + Amber Fantasy Theme === */

:root {
  --bg-base: #0d121b;
  --bg-surface: #0f141f;
  --bg-card: #0f1521;
  --bg-hover: #151c2a;
  --bg-input: #0a0f18;
  --gold: #d4a73a;
  --gold-dim: #b8922e;
  --gold-bright: #fbbf24;
  --red: #EF4444;
  --red-dim: #B91C1C;
  --green: #10B981;
  --green-dim: #059669;
  --blue: #3B82F6;
  --purple: #8B5CF6;
  --text: #c9d1d9;
  --text-dim: #8b949e;
  --text-muted: #6e7681;
  --border: rgba(255,255,255,.08);
  --border-gold: rgba(212, 167, 58, 0.3);
  --shadow: 0 4px 24px rgba(0,0,0,0.4);
  --radius: 8px;
  --radius-lg: 12px;
  --mobile-header-h: 50px;
}

*, *::before, *::after { box-sizing: border-box; margin: 0; padding: 0; }

body {
  font-family: 'JetBrains Mono', monospace;
  font-size: 13px;
  background: var(--bg-base);
  color: var(--text);
  min-height: 100vh;
  overflow-x: hidden;
  padding-left: 56px;
}

body::before {
  content: '';
  position: fixed;
  inset: 0;
  pointer-events: none;
  z-index: 0;
  background-image: linear-gradient(rgba(255,255,255,.024) 1px, transparent 1px),
    linear-gradient(90deg, rgba(255,255,255,.024) 1px, transparent 1px);
  background-size: 48px 48px;
}

::selection { background: rgba(212,167,58,.25); color: #fff; }

.cinzel { font-family: 'Cinzel', serif; }

/* === Scrollbar === */
::-webkit-scrollbar { width: 6px; height: 6px; }
::-webkit-scrollbar-track { background: var(--bg-base); }
::-webkit-scrollbar-thumb { background: rgba(212,167,58,.3); border-radius: 3px; }
::-webkit-scrollbar-thumb:hover { background: rgba(212,167,58,.5); }

/* === Screens === */
.screen { display: none; }
.screen.active { display: flex; }

/* === LOGIN === */
#login-screen {
  min-height: 100vh;
  align-items: center;
  justify-content: center;
  background: radial-gradient(ellipse at center, #0f141f 0%, #0d121b 70%);
}

.login-container {
  background: var(--bg-card);
  border: 1px solid var(--border-gold);
  border-radius: var(--radius-lg);
  padding: 2.5rem;
  width: 420px;
  max-width: 95vw;
  box-shadow: var(--shadow), 0 0 60px rgba(212,167,58,0.05);
}

.login-logo {
  text-align: center;
  margin-bottom: 2rem;
}

.dragon-icon {
  font-size: 4rem;
  margin-bottom: 0.5rem;
  filter: drop-shadow(0 0 20px rgba(212,167,58,0.3));
}

.login-logo h1 {
  color: var(--gold);
  font-size: 2rem;
  letter-spacing: 4px;
  text-shadow: 0 0 30px rgba(212,167,58,0.2);
}

.login-logo .subtitle {
  color: var(--text-dim);
  font-size: 0.85rem;
  margin-top: 0.25rem;
  letter-spacing: 2px;
}

.login-tabs {
  display: flex;
  gap: 0;
  margin-bottom: 1.5rem;
  border-radius: var(--radius);
  overflow: hidden;
  border: 1px solid var(--border);
}

.login-tab {
  flex: 1;
  padding: 0.7rem;
  background: var(--bg-surface);
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  font-weight: 500;
  transition: all 0.2s;
}

.login-tab.active {
  background: var(--gold);
  color: var(--bg-base);
  font-weight: 600;
}

.login-panel { display: none; }
.login-panel.active { display: block; }

/* === Forms === */
.form-group {
  margin-bottom: 1rem;
}

.form-group label {
  display: block;
  font-size: 0.8rem;
  color: var(--text-dim);
  margin-bottom: 0.3rem;
  font-weight: 500;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

input[type="text"], input[type="number"], select, textarea {
  width: 100%;
  padding: 0.6rem 0.8rem;
  background: var(--bg-input);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
  font-size: 0.95rem;
  font-family: inherit;
  transition: border-color 0.2s;
}

input:focus, select:focus, textarea:focus {
  outline: none;
  border-color: var(--gold);
  box-shadow: 0 0 0 2px rgba(212,167,58,0.15);
}

textarea {
  resize: vertical;
  min-height: 120px;
}

/* === Buttons === */
.btn-gold {
  width: 100%;
  padding: 0.8rem 1.5rem;
  background: linear-gradient(135deg, var(--gold), var(--gold-dim));
  color: var(--bg-base);
  border: none;
  border-radius: var(--radius);
  font-weight: 700;
  font-size: 1rem;
  cursor: pointer;
  transition: all 0.2s;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 0.5rem;
}

.btn-gold:hover {
  background: linear-gradient(135deg, var(--gold-bright), var(--gold));
  transform: translateY(-1px);
  box-shadow: 0 4px 15px rgba(212,167,58,0.3);
}

.btn-sm {
  padding: 0.4rem 0.8rem;
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  color: var(--text);
  font-size: 0.8rem;
  cursor: pointer;
  transition: all 0.2s;
  white-space: nowrap;
}

.btn-sm:hover { border-color: var(--gold); color: var(--gold); }
.btn-sm.btn-gold { background: var(--gold); color: var(--bg-base); border-color: var(--gold); }
.btn-sm.btn-gold:hover { background: var(--gold-bright); }
.btn-sm.btn-danger, .btn-danger { background: var(--red-dim); color: white; border-color: var(--red-dim); }
.btn-sm.btn-danger:hover, .btn-danger:hover { background: var(--red); }
.btn-danger-sm { background: none; border: 1px solid var(--red-dim); color: var(--red); padding: 0.4rem 0.8rem; border-radius: var(--radius); cursor: pointer; font-size: 0.75rem; width: 100%; }
.btn-danger-sm:hover { background: var(--red-dim); color: white; }
.btn-lg { font-size: 1.2rem; padding: 1rem 2rem; }

.error-msg { color: var(--red); text-align: center; margin-top: 1rem; font-size: 0.85rem; }

/* Guide Link on Login Screen */
.guide-link-container {
  text-align: center;
  margin-top: 1.25rem;
  padding-top: 1rem;
  border-top: 1px solid var(--border);
}

.guide-link {
  color: var(--text-dim);
  text-decoration: none;
  font-size: 0.9rem;
  padding: 8px 16px;
  border-radius: var(--radius);
  transition: all 0.2s;
  display: inline-flex;
  align-items: center;
  gap: 4px;
}

.guide-link:hover {
  color: var(--gold);
  background: rgba(212, 167, 58, 0.08);
}

.hidden { display: none !important; }
.muted { color: var(--text-muted); font-style: italic; }

/* === APP LAYOUT === */
#app-screen {
  height: 100vh;
  overflow: hidden;
}

#sidebar {
  width: 240px;
  min-width: 240px;
  background: var(--bg-surface);
  border-right: 1px solid var(--border);
  display: flex;
  flex-direction: column;
  height: 100vh;
  overflow-y: auto;
}

.sidebar-header {
  padding: 1.2rem 1rem;
  display: flex;
  align-items: center;
  gap: 0.6rem;
  border-bottom: 1px solid var(--border);
}

.dragon-icon-sm { font-size: 1.5rem; }
.sidebar-header h2 { color: var(--gold); font-size: 1rem; letter-spacing: 3px; }

.room-info {
  padding: 0.8rem 1rem;
  border-bottom: 1px solid var(--border);
}

.room-pin-display {
  font-family: 'Courier New', monospace;
  font-size: 0.85rem;
  color: var(--gold);
}

.room-pin-display span {
  font-weight: 700;
  letter-spacing: 2px;
}

.player-info {
  margin-top: 0.3rem;
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.85rem;
}

.role-badge {
  font-size: 0.65rem;
  padding: 0.15rem 0.4rem;
  border-radius: 3px;
  font-weight: 600;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.role-badge.dm { background: var(--gold); color: var(--bg-base); }
.role-badge.player { background: var(--blue); color: white; }

.nav-links {
  padding: 0.5rem;
  flex-grow: 1;
}

.nav-btn {
  width: 100%;
  display: flex;
  align-items: center;
  gap: 0.7rem;
  padding: 0.65rem 0.8rem;
  background: none;
  border: none;
  color: var(--text-dim);
  cursor: pointer;
  border-radius: var(--radius);
  font-size: 0.9rem;
  transition: all 0.15s;
  text-align: left;
}

.nav-btn:hover { background: var(--bg-hover); color: var(--text); }
.nav-btn.active { background: var(--bg-hover); color: var(--gold); border-left: 3px solid var(--gold); }
.nav-icon { font-size: 1.1rem; width: 1.5rem; text-align: center; }

.sidebar-players {
  padding: 0.8rem 1rem;
  border-top: 1px solid var(--border);
}

.sidebar-players h3 {
  font-size: 0.7rem;
  text-transform: uppercase;
  color: var(--text-muted);
  letter-spacing: 1px;
  margin-bottom: 0.5rem;
}

.sidebar-players ul { list-style: none; }

.sidebar-players li {
  padding: 0.25rem 0;
  font-size: 0.8rem;
  color: var(--text-dim);
  display: flex;
  align-items: center;
  gap: 0.4rem;
}

.sidebar-players li::before {
  content: '●';
  color: var(--green);
  font-size: 0.5rem;
}

.sidebar-players li.dm-player { color: var(--gold); }

.sidebar-footer {
  padding: 0.8rem 1rem;
  border-top: 1px solid var(--border);
}

/* === Main Content === */
#main-content {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  padding: 1.5rem 2rem;
  height: 100vh;
}

.tab-content { display: none; }
.tab-content.active { display: block; }

.tab-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-bottom: 1.5rem;
  flex-wrap: wrap;
  gap: 0.8rem;
}

.tab-header h1 {
  color: var(--gold);
  font-size: 1.5rem;
  letter-spacing: 2px;
}

/* === CHARACTER SHEET === */
.char-actions {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.char-actions select {
  width: 200px;
}

.sheet-section {
  background: var(--bg-card);
  border: 1px solid var(--border);
  border-radius: var(--radius-lg);
  padding: 1.2rem;
  margin-bottom: 1rem;
}

.sheet-section h2 {
  font-family: 'Cinzel', serif;
  color: var(--gold);
  font-size: 1rem;
  margin-bottom: 0.8rem;
  letter-spacing: 1px;
}

.section-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  flex-wrap: wrap;
  gap: 0.5rem;
  margin-bottom: 0.8rem;
}

.section-header h2 { margin-bottom: 0; }

.form-row {
  display: flex;
  gap: 0.8rem;
  flex-wrap: wrap;
}

.form-row .form-group { flex: 1; min-width: 140px; }

.char-input {
  font-size: 0.95rem;
}

.char-input.cinzel {
  font-family: 'Cinzel', serif;
  font-size: 1.1rem;
  color: var(--gold);
}

/* Ability Scores */
.ability-method {
  display: flex;
  align-items: center;
  gap: 0.5rem;
  font-size: 0.8rem;
  color: var(--text-dim);
}

.ability-method select { width: auto; font-size: 0.8rem; padding: 0.3rem 0.5rem; }

.ability-scores-grid {
  display: grid;
  grid-template-columns: repeat(6, 1fr);
  gap: 0.8rem;
}

.ability-card {
  background: var(--bg-surface);
  border: 1px solid var(--border);
  border-radius: var(--radius);
  padding: 0.8rem 0.5rem;
  text-align: center;
  transition: border-color 0.2s;
}

.ability-card:hover { border-color: var(--gold-dim); }

.ability-card .ability-name {
  font-family: 'Cinzel', serif;
  font-size: 0.7rem;
  color: var(--gold);
  text-transform: uppercase;
  letter-spacing: 1px;
  margin-bottom: 0.3rem;
}

