const express = require('express');
const http = require('http');
const WebSocket = require('ws');
const { v4: uuidv4 } = require('uuid');
const fs = require('fs');
const path = require('path');
const cors = require('cors');

const app = express();
const server = http.createServer(app);
const wss = new WebSocket.Server({ server });

const PORT = 3004;
const DATA_DIR = path.join(__dirname, '..', 'data');

// Ensure data directory
if (!fs.existsSync(DATA_DIR)) fs.mkdirSync(DATA_DIR, { recursive: true });

app.use(cors());
app.use(express.json({ limit: '50mb' }));

// --- Data helpers ---
function readJSON(file) {
  const fp = path.join(DATA_DIR, file);
  if (!fs.existsSync(fp)) return {};
  try { return JSON.parse(fs.readFileSync(fp, 'utf8')); } catch { return {}; }
}

function writeJSON(file, data) {
  fs.writeFileSync(path.join(DATA_DIR, file), JSON.stringify(data, null, 2));
  // Auto-backup for rooms.json and characters.json
  if (file === 'rooms.json' || file === 'characters.json') {
    createBackup(file, data);
  }
}

// --- Backup system ---
const BACKUP_DIR = path.join(DATA_DIR, 'backups');
if (!fs.existsSync(BACKUP_DIR)) fs.mkdirSync(BACKUP_DIR, { recursive: true });

function createBackup(file, data) {
  try {
    const today = new Date().toISOString().slice(0, 10); // YYYY-MM-DD
    const baseName = file.replace('.json', '');
    const backupFile = path.join(BACKUP_DIR, `${baseName}-${today}.json`);
    fs.writeFileSync(backupFile, JSON.stringify(data, null, 2));
    cleanOldBackups(baseName);
  } catch (e) {
    console.error('Backup failed for', file, e.message);
  }
}

function cleanOldBackups(baseName) {
  try {
    const files = fs.readdirSync(BACKUP_DIR)
      .filter(f => f.startsWith(baseName + '-') && f.endsWith('.json'))
      .sort()
      .reverse();
    // Keep last 7 days
    const toDelete = files.slice(7);
    toDelete.forEach(f => {
      fs.unlinkSync(path.join(BACKUP_DIR, f));
    });
  } catch (e) {
    console.error('Backup cleanup failed:', e.message);
  }
}

function readArray(file) {
  const fp = path.join(DATA_DIR, file);
  if (!fs.existsSync(fp)) return [];
  try { return JSON.parse(fs.readFileSync(fp, 'utf8')); } catch { return []; }
}

function writeArray(file, data) {
  fs.writeFileSync(path.join(DATA_DIR, file), JSON.stringify(data, null, 2));
}

// --- PIN Generation Helpers ---
function generate6DigitPin(rooms) {
  let pin;
  do {
    pin = String(Math.floor(100000 + Math.random() * 900000));
  } while (rooms[pin]);
  return pin;
}

function generate4DigitPin(rooms) {
  // Must be unique across ALL rooms and ALL players
  const usedPins = new Set();
  for (const roomPin of Object.keys(rooms)) {
    const room = rooms[roomPin];
    if (room.players) {
      for (const p of room.players) {
        if (p.pin) usedPins.add(p.pin);
      }
    }
  }
  let pin;
  let attempts = 0;
  do {
    pin = String(Math.floor(1000 + Math.random() * 9000));
    attempts++;
    if (attempts > 5000) throw new Error('Could not generate unique 4-digit PIN');
  } while (usedPins.has(pin));
  return pin;
}

// --- WebSocket connections by room ---
const roomConnections = {}; // { roomPin: Set<ws> }
const wsUserMap = new WeakMap(); // ws -> { roomPin, userId, userName, isDM }

wss.on('connection', (ws) => {
  ws.isAlive = true;
  ws.on('pong', () => { ws.isAlive = true; });

  ws.on('message', (raw) => {
    let msg;
    try { msg = JSON.parse(raw); } catch { return; }

    switch (msg.type) {
      case 'join-room': {
        const { roomPin, userId, userName, isDM, isSpectator } = msg;
        wsUserMap.set(ws, { roomPin, userId, userName, isDM, isSpectator: isSpectator || false });
        if (!roomConnections[roomPin]) roomConnections[roomPin] = new Set();
        roomConnections[roomPin].add(ws);
        // Notify room
        broadcastToRoom(roomPin, { type: 'user-joined', userId, userName, isDM, isSpectator: isSpectator || false });
        // Send spectator count
        broadcastSpectatorCount(roomPin);
        // Send system chat message for join
        if (!isSpectator) {
          const joinMsg = { sender: 'System', text: `${userName} joined the room`, timestamp: Date.now(), isSystem: true };
          saveChatMessage(roomPin, joinMsg);
          broadcastToRoom(roomPin, { type: 'chat_message', data: joinMsg });
        }
        break;
      }
      case 'dice-roll': {
        const info = wsUserMap.get(ws);
        if (info) {
          const rollData = { ...msg, userId: info.userId, userName: info.userName, timestamp: Date.now() };
          // Save to roll history
          saveRollHistory(info.roomPin, rollData);
          broadcastToRoom(info.roomPin, { type: 'dice-roll', data: rollData });
        }
        break;
      }
      case 'initiative-update': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'initiative-update', data: msg.data });
        }
        break;
      }
      case 'character_update': {
        const info2 = wsUserMap.get(ws);
        if (info2) {
          broadcastToRoom(info2.roomPin, { type: 'character_update', data: msg.data, userId: info2.userId });
        }
        break;
      }
      case 'chat-message': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'chat-message', userId: info.userId, userName: info.userName, message: msg.message, timestamp: Date.now() });
        }
        break;
      }
      case 'player-added': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'player-added', data: msg.data });
        }
        break;
      }
      case 'player-removed': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'player-removed', data: msg.data });
        }
        break;
      }
      case 'map_update': {
        const info = wsUserMap.get(ws);
        if (info) {
          // Persist map state
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            rooms[info.roomPin].mapState = msg.data;
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'map_update', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'token_move': {
        const info = wsUserMap.get(ws);
        if (info) {
          // Persist token position
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            if (!rooms[info.roomPin].tokens) rooms[info.roomPin].tokens = {};
            if (msg.data && msg.data.id) {
              rooms[info.roomPin].tokens[msg.data.id] = { x: msg.data.x, y: msg.data.y, ...msg.data };
            }
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'token_move', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'grid_update': {
        const info = wsUserMap.get(ws);
        if (info) {
          // Persist grid settings
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            rooms[info.roomPin].gridSettings = msg.data;
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'grid_update', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'token_add': {
        const info = wsUserMap.get(ws);
        if (info) {
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            if (!rooms[info.roomPin].tokens) rooms[info.roomPin].tokens = {};
            if (msg.data && msg.data.id) {
              rooms[info.roomPin].tokens[msg.data.id] = msg.data;
            }
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'token_add', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'token_remove': {
        const info = wsUserMap.get(ws);
        if (info) {
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            if (rooms[info.roomPin].tokens && msg.data && msg.data.id) {
              delete rooms[info.roomPin].tokens[msg.data.id];
            }
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'token_remove', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'fog_reveal': {
        const info = wsUserMap.get(ws);
        if (info) {
          // Persist fog state
          const rooms = readJSON('rooms.json');
          if (rooms[info.roomPin]) {
            if (!rooms[info.roomPin].fogRevealed) rooms[info.roomPin].fogRevealed = [];
            rooms[info.roomPin].fogRevealed.push(msg.data);
            writeJSON('rooms.json', rooms);
          }
          broadcastToRoom(info.roomPin, { type: 'fog_reveal', data: msg.data, userId: info.userId });
        }
        break;
      }
      case 'achievement-unlocked': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'achievement-unlocked', data: msg.data });
        }
        break;
      }
      case 'loot-shared': {
        const info = wsUserMap.get(ws);
        if (info) {
          broadcastToRoom(info.roomPin, { type: 'loot-shared', data: msg.data });
        }
        break;
      }
      case 'chat_message': {
        const info = wsUserMap.get(ws);
        if (info && !info.isSpectator) {
          const chatData = {
            sender: info.userName,
            text: (msg.data && msg.data.text) || '',
            timestamp: Date.now(),
            isDM: info.isDM,
            isSystem: false
          };
          saveChatMessage(info.roomPin, chatData);
          broadcastToRoom(info.roomPin, { type: 'chat_message', data: chatData });
        }
        break;
      }
    }

    // Log events for session replay
    const wsInfo = wsUserMap.get(ws);
    if (wsInfo && wsInfo.roomPin) {
      const logTypes = ['dice-roll', 'initiative-update', 'chat-message', 'token_move'];
      if (logTypes.includes(msg.type)) {
        logSessionEvent(wsInfo.roomPin, {
          type: msg.type,
          data: msg.type === 'dice-roll'
            ? { userName: wsInfo.userName, notation: msg.notation, total: msg.total, results: msg.results, detail: msg.detail }
            : msg.type === 'chat-message'
            ? { userName: wsInfo.userName, message: msg.message }
            : msg.type === 'token_move'
            ? { userName: wsInfo.userName, tokenId: msg.data?.id, x: msg.data?.x, y: msg.data?.y }
            : { summary: 'Initiative updated' },
          timestamp: Date.now()
        });
      }
    }
  });

  ws.on('close', () => {
    const info = wsUserMap.get(ws);
    if (info && roomConnections[info.roomPin]) {
      roomConnections[info.roomPin].delete(ws);
      broadcastToRoom(info.roomPin, { type: 'user-left', userId: info.userId, userName: info.userName });
      // Send leave chat message
      if (!info.isSpectator) {
        const leaveMsg = { sender: 'System', text: `${info.userName} left the room`, timestamp: Date.now(), isSystem: true };
        saveChatMessage(info.roomPin, leaveMsg);
        broadcastToRoom(info.roomPin, { type: 'chat_message', data: leaveMsg });
      }
      broadcastSpectatorCount(info.roomPin);
      if (roomConnections[info.roomPin].size === 0) {
        delete roomConnections[info.roomPin];
      }
    }
  });
});

function broadcastToRoom(roomPin, data) {
  const conns = roomConnections[roomPin];
  if (!conns) return;
  const msg = JSON.stringify(data);
  for (const ws of conns) {
    if (ws.readyState === WebSocket.OPEN) ws.send(msg);
  }
}

function saveChatMessage(roomPin, chatData) {
  const rooms = readJSON('rooms.json');
  const room = rooms[roomPin];
  if (!room) return;
  if (!room.chatMessages) room.chatMessages = [];
  room.chatMessages.push(chatData);
  // Keep last 100
  if (room.chatMessages.length > 100) room.chatMessages = room.chatMessages.slice(-100);
  rooms[roomPin] = room;
  writeJSON('rooms.json', rooms);
}

function broadcastSpectatorCount(roomPin) {
  const conns = roomConnections[roomPin];
  if (!conns) return;
  let count = 0;
  for (const ws of conns) {
    const info = wsUserMap.get(ws);
    if (info && info.isSpectator) count++;
  }
  broadcastToRoom(roomPin, { type: 'spectator-count', count });
}

function saveRollHistory(roomPin, rollData) {
  const rooms = readJSON('rooms.json');
  const room = rooms[roomPin];
  if (!room) return;
  if (!room.rollHistory) room.rollHistory = [];
  room.rollHistory.push(rollData);
  if (room.rollHistory.length > 200) room.rollHistory = room.rollHistory.slice(-200);
  rooms[roomPin] = room;
  writeJSON('rooms.json', rooms);
}

function logSessionEvent(roomPin, event) {
  try {
    const rooms = readJSON('rooms.json');
    const room = rooms[roomPin];
    if (!room) return;
    if (!room.eventLog) room.eventLog = [];
    room.eventLog.push(event);
    if (room.eventLog.length > 1000) {
      room.eventLog = room.eventLog.slice(-1000);
    }
    rooms[roomPin] = room;
    writeJSON('rooms.json', rooms);
  } catch (e) {
    console.error('logSessionEvent error:', e.message);
  }
}

