});

// Helper: calculate max HP from character data
function calcMaxHP(c) {
  const CLASSES_DATA = [
    { name:'Barbarian', hitDie:'d12' }, { name:'Bard', hitDie:'d8' }, { name:'Cleric', hitDie:'d8' },
    { name:'Druid', hitDie:'d8' }, { name:'Fighter', hitDie:'d10' }, { name:'Monk', hitDie:'d8' },
    { name:'Paladin', hitDie:'d10' }, { name:'Ranger', hitDie:'d10' }, { name:'Rogue', hitDie:'d8' },
    { name:'Sorcerer', hitDie:'d6' }, { name:'Warlock', hitDie:'d8' }, { name:'Wizard', hitDie:'d6' }
  ];
  const cls = CLASSES_DATA.find(cl => cl.name === c.className);
  if (!cls) return 10;
  const hitDieMax = parseInt(cls.hitDie.replace('d', ''));
  const conScore = c.abilityScores?.CON || 10;
  const conMod = Math.floor((conScore - 10) / 2);
  let hp = hitDieMax + conMod;
  if ((c.level || 1) > 1) {
    hp += ((c.level || 1) - 1) * (Math.floor(hitDieMax / 2) + 1 + conMod);
  }
  if (c.species === 'Dwarf') hp += (c.level || 1);
  return Math.max(hp, 1);
}

