app.get('/api/rooms/:pin/analytics', (req, res) => {
  const rooms = readJSON('rooms.json');
  const room = rooms[req.params.pin];
  if (!room) return res.status(404).json({ error: 'Room not found' });

  const rollHistory = room.rollHistory || [];
  const initiative = room.initiative || { combatants: [] };
  const totalRolls = rollHistory.length;
  let totalDamage = 0, biggestHit = 0, biggestHitPlayer = '';
  const playerRollCounts = {};

  rollHistory.forEach(r => {
    const name = r.userName || 'Unknown';
    playerRollCounts[name] = (playerRollCounts[name] || 0) + 1;
    if (r.sides && r.sides !== 20 && r.total > 0) {
      totalDamage += r.total;
      if (r.total > biggestHit) { biggestHit = r.total; biggestHitPlayer = name; }
    }
  });

  let mostActivePlayer = '', mostActiveRolls = 0;
  for (const [name, count] of Object.entries(playerRollCounts)) {
    if (count > mostActiveRolls) { mostActiveRolls = count; mostActivePlayer = name; }
  }

  const combatRounds = initiative.active ? initiative.currentTurn : 0;
  let sessionDuration = 0;
  if (rollHistory.length > 1) {
    const first = rollHistory[0]?.timestamp || 0;
    const last = rollHistory[rollHistory.length - 1]?.timestamp || 0;
    sessionDuration = last - first;
  }

  const participation = {};
  const totalPlayerRolls = Object.values(playerRollCounts).reduce((s, c) => s + c, 0) || 1;
  for (const [name, count] of Object.entries(playerRollCounts)) {
    participation[name] = Math.round((count / totalPlayerRolls) * 100);
  }

  res.json({ totalRolls, totalDamage, combatRounds, sessionDuration, mostActivePlayer, mostActiveRolls, biggestHit, biggestHitPlayer, participation, playerRollCounts });
});

