app.post('/api/quests/generate', async (req, res) => {
  const { setting, difficulty, partyLevel, theme, extras } = req.body;
  if (!setting) return res.status(400).json({ error: 'Setting required' });

  const aiPrompt = `Generate a D&D 2024 quest. Setting: ${setting}. Party level: ${partyLevel || 3}. Difficulty: ${difficulty || 'Medium'}. Theme: ${theme || 'Mixed'}. ${extras ? 'Additional details: ' + extras : ''} Return ONLY valid JSON (no markdown, no code fences) with: {"title": string, "hook": string (1 paragraph), "objectives": [string array], "encounters": [{"name": string, "cr": string, "description": string}], "npcs": [{"name": string, "role": string, "motivation": string}], "rewards": [string array], "twists": [string array], "estimatedSessions": string}`;

  try {
    const response = await fetch('http://127.0.0.1:3001/voice/chat', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ agentId: 'sarael', message: aiPrompt })
    });
    const data = await response.json();
    const rawText = data.response || data.message || '{}';

    let questData;
    try { questData = JSON.parse(rawText); } catch {
      const fenceMatch = rawText.match(/```(?:json)?\s*([\s\S]*?)```/);
      if (fenceMatch) try { questData = JSON.parse(fenceMatch[1].trim()); } catch {}
      if (!questData) {
        const jsonMatch = rawText.match(/\{[\s\S]*\}/);
        if (jsonMatch) try { questData = JSON.parse(jsonMatch[0]); } catch {}
      }
      if (!questData) return res.status(500).json({ error: 'AI returned invalid JSON' });
    }

    res.json({
      title: questData.title || 'Untitled Quest',
      hook: questData.hook || '',
      objectives: Array.isArray(questData.objectives) ? questData.objectives : [],
      encounters: Array.isArray(questData.encounters) ? questData.encounters : [],
      npcs: Array.isArray(questData.npcs) ? questData.npcs : [],
      rewards: Array.isArray(questData.rewards) ? questData.rewards : [],
      twists: Array.isArray(questData.twists) ? questData.twists : [],
      estimatedSessions: questData.estimatedSessions || '1-2'
    });
  } catch (err) {
    res.status(500).json({ error: 'AI service unavailable: ' + err.message });
  }
});

