// Generic search helper (kept for legacy chargen)
function searchSRD(items, query) {
  if (!query) return items;
  const q = query.toLowerCase();
  return items.filter(item => {
    const name = (item.name || '').toLowerCase();
    const desc = (item.desc || item.description || '').toString().toLowerCase();
    const index = (item.index || '').toLowerCase();
    return name.includes(q) || desc.includes(q) || index.includes(q);
  });
}

function getSRDData(category, edition) {
  const ed = edition === '2014' ? '2014' : '2024';
  return SRD[ed][category] || SRD['2014'][category] || [];
}

// Compendium search helper
function searchCompendium(items, query) {
  if (!query) return items;
  const q = query.toLowerCase();
  return items.filter(item => {
    const name = (item.name || '').toLowerCase();
    const entries = (item.entries || item.description || '').toString().toLowerCase();
    return name.includes(q) || entries.includes(q);
  });
}

// Pagination helper
function paginate(data, page, limit) {
  const p = Math.max(1, parseInt(page) || 1);
  const l = Math.min(200, Math.max(1, parseInt(limit) || 50));
  const start = (p - 1) * l;
  return {
    data: data.slice(start, start + l),
    total: data.length,
    page: p,
    limit: l,
    totalPages: Math.ceil(data.length / l),
  };
}

