    data = data.filter(s => s.level === lvl);
  }
  if (school) {
    const sch = school.toLowerCase();
    data = data.filter(s => (s.school || '').toLowerCase().includes(sch));
  }
  if (className) {
    const cls = className.toLowerCase();
    data = data.filter(s => Array.isArray(s.classes) && s.classes.some(c => (c || '').toLowerCase() === cls));
  }
  if (source) data = data.filter(s => s.source === source);
  if (page || limit) return res.json(paginate(data, page, limit));
  res.json(data);
});

